namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public List<int> Ratings { get; set; } = [];

    public double AverageRating =>
        Ratings.Count > 0 ? Math.Round(Ratings.Average(), 1) : 0;

    public int RatingCount => Ratings.Count;
}

public class RecipeCategory
{
    public string Name { get; set; } = string.Empty;
    public string Icon { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int RecipeCount { get; set; }
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Description = "A simple and delicious pizza with fresh mozzarella, tomatoes, and basil.",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
            Steps =
            [
                "Preheat oven to 475°F (245°C).",
                "Roll out the dough on a floured surface.",
                "Spread crushed tomatoes evenly over the dough.",
                "Tear mozzarella into pieces and distribute over the sauce.",
                "Bake for 10-12 minutes until crust is golden.",
                "Top with fresh basil and a drizzle of olive oil."
            ],
            Ratings = [5, 4, 5, 5, 4]
        },
        new()
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Description = "Creamy pasta made with eggs, cheese, pancetta, and black pepper.",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Pecorino Romano", "Black pepper", "Salt"],
            Steps =
            [
                "Cook spaghetti in salted boiling water until al dente.",
                "Cook pancetta in a skillet until crispy.",
                "Whisk eggs and grated Pecorino together.",
                "Toss hot pasta with pancetta, then remove from heat.",
                "Quickly stir in the egg mixture, tossing to coat.",
                "Season generously with black pepper and serve."
            ],
            Ratings = [5, 5, 4, 5]
        },
        new()
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Description = "Tender chicken pieces in a rich and creamy spiced tomato sauce.",
            Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
            Steps =
            [
                "Marinate chicken in yogurt and spices for at least 1 hour.",
                "Grill or broil chicken until charred.",
                "Sauté onion, garlic, and ginger in a pan.",
                "Add tomato sauce and simmer for 15 minutes.",
                "Stir in cream and garam masala.",
                "Add chicken pieces and simmer for 10 more minutes."
            ],
            Ratings = [5, 4, 4, 5, 5]
        },
        new()
        {
            Id = 4, Title = "Vegetable Pad Thai", Category = "Asian",
            Description = "A vibrant stir-fried noodle dish loaded with vegetables and a tangy sauce.",
            Ingredients = ["Rice noodles", "Tofu", "Bean sprouts", "Peanuts", "Lime", "Tamarind paste", "Fish sauce", "Eggs"],
            Steps =
            [
                "Soak rice noodles in warm water for 30 minutes.",
                "Mix tamarind paste, fish sauce, and sugar for the sauce.",
                "Stir-fry tofu until golden, set aside.",
                "Scramble eggs in the same wok.",
                "Add noodles and sauce, toss until coated.",
                "Add tofu and bean sprouts, garnish with peanuts and lime."
            ],
            Ratings = [4, 5, 4]
        },
        new()
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Description = "Seasoned ground beef in crispy taco shells with fresh toppings.",
            Ingredients = ["Ground beef", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Taco seasoning"],
            Steps =
            [
                "Brown ground beef in a skillet over medium heat.",
                "Add taco seasoning and water, simmer until thickened.",
                "Warm taco shells in the oven.",
                "Fill shells with seasoned beef.",
                "Top with lettuce, tomato, cheese, and sour cream.",
                "Serve immediately with salsa on the side."
            ],
            Ratings = [4, 4, 5, 4, 3]
        },
        new()
        {
            Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts",
            Description = "Rich chocolate cakes with a molten center, perfect for any occasion.",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
            Steps =
            [
                "Preheat oven to 425°F (220°C) and grease ramekins.",
                "Melt chocolate and butter together.",
                "Whisk eggs, sugar, and vanilla until thick.",
                "Fold chocolate mixture into the eggs, then add flour.",
                "Pour into ramekins and bake for 12-14 minutes.",
                "Invert onto plates and serve immediately."
            ],
            Ratings = [5, 5, 5, 4, 5]
        },
        new()
        {
            Id = 7, Title = "Caesar Salad", Category = "Salads",
            Description = "Crisp romaine lettuce with creamy Caesar dressing, croutons, and Parmesan.",
            Ingredients = ["Romaine lettuce", "Caesar dressing", "Croutons", "Parmesan cheese", "Lemon", "Anchovy paste"],
            Steps =
            [
                "Wash and chop romaine lettuce into bite-sized pieces.",
                "Make dressing by whisking anchovy paste, lemon, and garlic.",
                "Toss lettuce with dressing until evenly coated.",
                "Add croutons and shaved Parmesan.",
                "Season with black pepper and serve chilled."
            ],
            Ratings = [4, 3, 4, 4]
        },
        new()
        {
            Id = 8, Title = "Guacamole", Category = "Mexican",
            Description = "Fresh and creamy avocado dip with lime, cilantro, and jalapeño.",
            Ingredients = ["Avocados", "Lime", "Cilantro", "Red onion", "Jalapeño", "Tomato", "Salt"],
            Steps =
            [
                "Halve and pit ripe avocados, scoop into a bowl.",
                "Mash to desired consistency.",
                "Stir in diced onion, tomato, and jalapeño.",
                "Add chopped cilantro and lime juice.",
                "Season with salt and serve with tortilla chips."
            ],
            Ratings = [5, 4, 5]
        }
    ];

    private int _nextId = 9;

    public List<RecipeCategory> GetCategories()
    {
        return _recipes
            .GroupBy(r => r.Category)
            .Select(g => new RecipeCategory
            {
                Name = g.Key,
                Icon = GetCategoryIcon(g.Key),
                Description = GetCategoryDescription(g.Key),
                RecipeCount = g.Count()
            })
            .OrderBy(c => c.Name)
            .ToList();
    }

    public List<Recipe> GetRecipesByCategory(string category)
    {
        return _recipes
            .Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase))
            .ToList();
    }

    public Recipe? GetRecipeById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int rating)
    {
        var recipe = GetRecipeById(recipeId);
        if (recipe is not null && rating is >= 1 and <= 5)
        {
            recipe.Ratings.Add(rating);
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    private static string GetCategoryIcon(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Asian" => "🥢",
        "Mexican" => "🌮",
        "Desserts" => "🍰",
        "Salads" => "🥗",
        _ => "🍽️"
    };

    private static string GetCategoryDescription(string category) => category switch
    {
        "Italian" => "Classic pasta, pizza, and Mediterranean flavors",
        "Indian" => "Rich curries, aromatic spices, and traditional dishes",
        "Asian" => "Stir-fries, noodles, and bold East Asian flavors",
        "Mexican" => "Tacos, salsas, and vibrant Latin cuisine",
        "Desserts" => "Sweet treats, cakes, and indulgent finishes",
        "Salads" => "Fresh, healthy, and colorful salad creations",
        _ => "Delicious recipes to explore"
    };
}

