arguments.file_text:
@rendermode InteractiveServer

<div class="star-rating d-inline-flex align-items-center gap-2">
    <div class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= (_hoverRating ?? _selectedRating) ? "filled" : "")"
                  @onclick="() => SubmitRating(star)"
                  @onmouseover="() => _hoverRating = star"
                  @onmouseout="() => _hoverRating = null"
                  role="button"
                  title="Rate @star star(s)">
                ★
            </span>
        }
    </div>
    @if (AverageRating > 0)
    {
        <span class="rating-info text-muted">
            @AverageRating.ToString("0.0") / 5 (@RatingCount ratings)
        </span>
    }
    @if (_submitted)
    {
        <span class="text-success fw-bold">✓ Rated!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int RatingCount { get; set; }
    [Parameter] public EventCallback<int> OnRated { get; set; }

    private int _selectedRating;
    private int? _hoverRating;
    private bool _submitted;

    private async Task SubmitRating(int rating)
    {
        _selectedRating = rating;
        _submitted = true;
        await OnRated.InvokeAsync(rating);
    }
}

.star-rating .stars {
    font-size: 1.8rem;
    cursor: pointer;
    user-select: none;
}

.star-rating .star {
    color: #ccc;
    transition: color 0.15s ease, transform 0.15s ease;
    display: inline-block;
}

.star-rating .star:hover,
.star-rating .star.filled {
    color: #ffc107;
}

.star-rating .star:hover {
    transform: scale(1.2);
}

.rating-info {
    font-size: 0.9rem;
}

.category-card {
    transition: transform 0.2s ease, box-shadow 0.2s ease;
    border: 1px solid #e0e0e0;
}

.category-card:hover {
    transform: translateY(-4px);
    box-shadow: 0 6px 20px rgba(0, 0, 0, 0.12) !important;
}

@page "/category/{CategoryName}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models

@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes</PageTitle>

<nav aria-label="breadcrumb" class="mb-3">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h2>@CategoryName Recipes</h2>

@if (_recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4 mt-2">
        @foreach (var recipe in _recipes)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">
                            <a href="/recipe/@recipe.Id" class="text-decoration-none">@recipe.Title</a>
                        </h5>
                        <p class="card-text text-muted">@recipe.Description</p>
                        <div class="d-flex justify-content-between align-items-center">
                            <small class="text-warning">
                                @for (int i = 0; i < (int)Math.Round(recipe.AverageRating); i++)
                                {
                                    <span>★</span>
                                }
                                @for (int i = (int)Math.Round(recipe.AverageRating); i < 5; i++)
                                {
                                    <span class="text-muted">★</span>
                                }
                            </small>
                            <small class="text-muted">@recipe.RatingCount ratings</small>
                        </div>
                    </div>
                    <div class="card-footer bg-transparent">
                        <a href="/recipe/@recipe.Id" class="btn btn-outline-primary btn-sm">View Recipe →</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private List<Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        _recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models

@inject RecipeService RecipeService

@if (_recipe is null)
{
    <PageTitle>Recipe Not Found</PageTitle>
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <PageTitle>@_recipe.Title</PageTitle>

    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/category/@_recipe.Category">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h1>@_recipe.Title</h1>
            <p class="lead text-muted">@_recipe.Description</p>

            <div class="mb-4">
                <StarRating RecipeId="@_recipe.Id"
                            AverageRating="@_recipe.AverageRating"
                            RatingCount="@_recipe.RatingCount"
                            OnRated="HandleRating" />
            </div>

            <div class="card mb-4">
                <div class="card-header">
                    <h4 class="mb-0">🥘 Ingredients</h4>
                </div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in _recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>

            <div class="card mb-4">
                <div class="card-header">
                    <h4 class="mb-0">📋 Steps</h4>
                </div>
                <div class="card-body">
                    <ol class="mb-0">
                        @foreach (var step in _recipe.Steps)
                        {
                            <li class="mb-2">@step</li>
                        }
                    </ol>
                </div>
            </div>
        </div>

        <div class="col-lg-4">
            <div class="card shadow-sm">
                <div class="card-body text-center">
                    <h5>Recipe Info</h5>
                    <hr />
                    <p><strong>Category:</strong> <a href="/category/@_recipe.Category">@_recipe.Category</a></p>
                    <p><strong>Ingredients:</strong> @_recipe.Ingredients.Count items</p>
                    <p><strong>Steps:</strong> @_recipe.Steps.Count</p>
                    <p><strong>Rating:</strong> @_recipe.AverageRating.ToString("0.0") ★</p>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetRecipeById(Id);
    }

    private void HandleRating(int rating)
    {
        RecipeService.AddRating(Id, rating);
        _recipe = RecipeService.GetRecipeById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Services
@using RecipeCommunity.Models

@inject RecipeService RecipeService

<PageTitle>Submit a Recipe</PageTitle>

<h2>📝 Submit a Recipe</h2>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>🎉 Recipe submitted successfully!</h4>
        <p>Your recipe "<strong>@_title</strong>" has been added to the <strong>@_category</strong> category.</p>
        <a href="/category/@_category" class="btn btn-primary">View in @_category →</a>
        <button class="btn btn-outline-secondary ms-2" @onclick="ResetForm">Submit Another</button>
    </div>
}
