@rendermode InteractiveServer

<div class="star-rating d-inline-flex align-items-center gap-2">
    <div class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= (_hoverRating ?? _selectedRating) ? "filled" : "")"
                  @onclick="() => SubmitRating(star)"
                  @onmouseover="() => _hoverRating = star"
                  @onmouseout="() => _hoverRating = null"
                  role="button"
                  title="Rate @star star(s)">
                ★
            </span>
        }
    </div>
    @if (AverageRating > 0)
    {
        <span class="rating-info text-muted">
            @AverageRating.ToString("0.0") / 5 (@RatingCount ratings)
        </span>
    }
    @if (_submitted)
    {
        <span class="text-success fw-bold">✓ Rated!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int RatingCount { get; set; }
    [Parameter] public EventCallback<int> OnRated { get; set; }

    private int _selectedRating;
    private int? _hoverRating;
    private bool _submitted;

    private async Task SubmitRating(int rating)
    {
        _selectedRating = rating;
        _submitted = true;
        await OnRated.InvokeAsync(rating);
    }
}

.star-rating .stars {
    font-size: 1.8rem;
    cursor: pointer;
    user-select: none;
}

.star-rating .star {
    color: #ccc;
    transition: color 0.15s ease, transform 0.15s ease;
    display: inline-block;
}

.star-rating .star:hover,
.star-rating .star.filled {
    color: #ffc107;
}

.star-rating .star:hover {
    transform: scale(1.2);
}

.rating-info {
    font-size: 0.9rem;
}

.category-card {
    transition: transform 0.2s ease, box-shadow 0.2s ease;
    border: 1px solid #e0e0e0;
}

.category-card:hover {
    transform: translateY(-4px);
    box-shadow: 0 6px 20px rgba(0, 0, 0, 0.12) !important;
}

