<div class="star-rating d-inline-flex align-items-center gap-2">
    <div class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= (_hoverRating ?? _selectedRating) ? "filled" : "")"
                  @onclick="() => SubmitRating(star)"
                  @onmouseover="() => _hoverRating = star"
                  @onmouseout="() => _hoverRating = null"
                  role="button"
                  title="Rate @star star(s)">
                ★
            </span>
        }
    </div>
    @if (AverageRating > 0)
    {
        <span class="rating-info text-muted">
            @AverageRating.ToString("0.0") / 5 (@RatingCount ratings)
        </span>
    }
    @if (_submitted)
    {
        <span class="text-success fw-bold">✓ Rated!</span>
    }
</div>

