    [Parameter] public int RatingCount { get; set; }
    [Parameter] public EventCallback<int> OnRated { get; set; }

    private int _selectedRating;
    private int? _hoverRating;
    private bool _submitted;

    private async Task SubmitRating(int rating)
    {
        _selectedRating = rating;
        _submitted = true;
        await OnRated.InvokeAsync(rating);
    }
}

